from prefect import flow, task
from prefect.artifacts import create_markdown_artifact
import subprocess

@task(retries=2, retry_delay_seconds=30)
def collect_and_filter_data(trajectory_dir: str, output_path: str) -> int:
    """Filter trajectories and return the count of examples."""
    from data_prep import build_sft_dataset
    return build_sft_dataset(trajectory_dir, output_path)

@task
def run_training(dataset_path: str, output_dir: str) -> str:
    """Launch training in a subprocess (or submit to a Kubernetes job)."""
    result = subprocess.run(
        ["python", "train_sft.py",
         "--dataset", dataset_path,
         "--output", output_dir],
        check=True, capture_output=True, text=True
    )
    return output_dir

@task
def evaluate_checkpoint(checkpoint_dir: str, eval_dataset: str) -> dict:
    """Run benchmark evaluation and return metrics."""
    # In practice: run lm-evaluation-harness or a custom eval script
    metrics = {"tool_call_accuracy": 0.91, "task_success_rate": 0.87}
    return metrics

@task
def register_model(checkpoint_dir: str, metrics: dict, registry_uri: str) -> str:
    """Register the model in MLflow if it passes quality gates."""
    import mlflow
    if metrics["task_success_rate"] < 0.80:
        raise ValueError(f"Quality gate failed: task_success_rate={metrics['task_success_rate']}")
    mlflow.set_tracking_uri(registry_uri)
    with mlflow.start_run():
        mlflow.log_metrics(metrics)
        mlflow.log_artifacts(checkpoint_dir)
        run_id = mlflow.active_run().info.run_id
    return run_id

@flow(name="agent-training-pipeline")
def agent_training_pipeline(
    trajectory_dir: str = "logs/trajectories",
    registry_uri: str = "http://mlflow:5000",
):
    n_examples = collect_and_filter_data(trajectory_dir, "data/sft_train.jsonl")
    checkpoint = run_training("data/sft_train.jsonl", "checkpoints/latest")
    metrics = evaluate_checkpoint(checkpoint, "data/eval.jsonl")
    run_id = register_model(checkpoint, metrics, registry_uri)
    create_markdown_artifact(
        key="training-summary",
        markdown=f"## Run complete\n- Examples: {n_examples}\n- Metrics: {metrics}\n- MLflow run: {run_id}"
    )
    return run_id

if __name__ == "__main__":
    agent_training_pipeline()
